import React, { useState } from 'react';
import { db } from '../services/firebase';
import { doc, writeBatch, setDoc, collection, addDoc, deleteDoc } from 'firebase/firestore';
import { Button } from './ui/Button';
import { Upload, FileJson, CheckCircle, AlertCircle, Database, FileText, Sparkles, Loader2, List, Activity, Wifi } from 'lucide-react';
import { createDocId, generateSyllabusList, generateFullUnitPack } from '../services/geminiService';
import { Language } from '../types';

export const AdminDataUpload: React.FC = () => {
    const [mode, setMode] = useState<'manual' | 'auto'>('manual');
    const [uploadType, setUploadType] = useState<'syllabus' | 'pack'>('pack');
    const [grade, setGrade] = useState('10 ශ්‍රේණිය (Grade 10)');
    const [language, setLanguage] = useState<Language>('si');
    const [subject, setSubject] = useState('');

    // Manual State
    const [jsonContent, setJsonContent] = useState<string>('');
    const [isUploading, setIsUploading] = useState(false);

    // Auto State
    const [units, setUnits] = useState<string[]>([]);
    const [selectedUnits, setSelectedUnits] = useState<string[]>([]);
    const [isFetchingUnits, setIsFetchingUnits] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const [genProgress, setGenProgress] = useState(0);

    const [logs, setLogs] = useState<string[]>([]);

    const grades = [
        "6 ශ්‍රේණිය (Grade 6)", "7 ශ්‍රේණිය (Grade 7)", "8 ශ්‍රේණිය (Grade 8)", 
        "9 ශ්‍රේණිය (Grade 9)", "10 ශ්‍රේණිය (Grade 10)", "11 ශ්‍රේණිය (Grade 11)",
        "12 ශ්‍රේණිය (Grade 12)", "13 ශ්‍රේණිය (Grade 13)"
    ];

    const addLog = (msg: string) => setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

    // --- CONNECTION TESTER ---
    const handleTestConnection = async () => {
        if (!db) {
            addLog("❌ Error: Firestore instance is null. Check services/firebase.ts");
            return;
        }

        setIsUploading(true);
        addLog("🔄 Testing Firestore Connection...");

        try {
            // 1. Test Write
            const testCol = collection(db, '_connection_test');
            const docRef = await addDoc(testCol, {
                timestamp: new Date().toISOString(),
                test: true,
                platform: 'web'
            });
            addLog(`✅ Write Success: Created Doc ID ${docRef.id}`);

            // 2. Test Delete (Cleanup)
            await deleteDoc(docRef);
            addLog("✅ Delete Success: Cleaned up test document.");

            addLog("🎉 FIRESTORE IS WORKING PERFECTLY!");

        } catch (e: any) {
            console.error(e);
            addLog(`❌ CONNECTION FAILED: ${e.code || e.message}`);
            if (e.message.includes("offline")) addLog("👉 Check your internet connection.");
            if (e.message.includes("permission") || e.code === "permission-denied") addLog("👉 Check Firestore Security Rules in Firebase Console.");
        } finally {
            setIsUploading(false);
        }
    };

    // --- MANUAL HANDLERS ---
    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            if (event.target?.result) {
                setJsonContent(event.target.result as string);
                setLogs(prev => [...prev, `File loaded: ${file.name}`]);
            }
        };
        reader.readAsText(file);
    };

    const handleUpload = async () => {
        if (!db) { addLog("Error: Firebase not initialized."); return; }
        if (!jsonContent) { addLog("Error: No JSON content loaded."); return; }

        setIsUploading(true);
        const batch = writeBatch(db);
        let opCount = 0;

        try {
            const data = JSON.parse(jsonContent);

            if (uploadType === 'syllabus') {
                if (!subject) {
                    addLog("Error: Subject is required for Syllabus upload.");
                    setIsUploading(false);
                    return;
                }
                const docRef = doc(db, 'syllabus', grade);
                const payload = { [subject]: data };
                batch.set(docRef, payload, { merge: true }); // Use merge to avoid overwriting
                opCount++;
                addLog(`Queued Syllabus for ${grade} - ${subject}`);
            } 
            else if (uploadType === 'pack') {
                if (!subject) {
                    addLog("Error: Subject is required for Study Pack upload.");
                    setIsUploading(false);
                    return;
                }

                for (const [unitName, content] of Object.entries(data)) {
                    const unitData = content as any;
                    const safeUnitName = unitName.replace(/Unit \d+[:.]\s*/i, '');

                    if (unitData.quiz && Array.isArray(unitData.quiz)) {
                        const quizId = createDocId(grade, subject, safeUnitName, 'medium', language);
                        const quizRef = doc(db, 'quizzes', quizId);
                        batch.set(quizRef, { 
                            questions: unitData.quiz,
                            createdAt: new Date().toISOString(),
                            source: 'admin_upload'
                        });
                        opCount++;
                    }

                    if (unitData.flashcards && Array.isArray(unitData.flashcards)) {
                        const flashId = createDocId(grade, subject, safeUnitName, language);
                        const flashRef = doc(db, 'flashcards', flashId);
                        batch.set(flashRef, { 
                            cards: unitData.flashcards,
                            createdAt: new Date().toISOString(),
                            source: 'admin_upload'
                        });
                        opCount++;
                    }
                }
            }

            if (opCount > 0) {
                await batch.commit();
                addLog(`✅ SUCCESS: Committed ${opCount} documents.`);
                setJsonContent('');
            } else {
                addLog("⚠️ Warning: No valid data found to upload.");
            }

        } catch (e: any) {
            console.error(e);
            addLog(`❌ ERROR: ${e.message}`);
        } finally {
            setIsUploading(false);
        }
    };

    // --- AUTO HANDLERS ---
    const handleFetchUnits = async () => {
        if (!subject) return;
        setIsFetchingUnits(true);
        setUnits([]);
        setSelectedUnits([]);
        addLog(`Fetching unit list for ${grade} ${subject}...`);

        try {
            const fetched = await generateSyllabusList(grade, subject, language);
            setUnits(fetched);
            addLog(`Found ${fetched.length} units.`);
        } catch (e: any) {
            addLog(`Error fetching units: ${e.message}`);
        } finally {
            setIsFetchingUnits(false);
        }
    };

    const handleGenerateAll = async () => {
        if (selectedUnits.length === 0) return;
        setIsGenerating(true);
        setGenProgress(0);
        addLog(`Starting AI generation for ${selectedUnits.length} units...`);

        try {
            for (let i = 0; i < selectedUnits.length; i++) {
                const unit = selectedUnits[i];
                const safeUnitName = unit.replace(/Unit \d+[:.]\s*/i, '');

                addLog(`Generating content for: ${unit}...`);

                // 1. Ask AI
                const pack = await generateFullUnitPack(grade, subject, unit, language);

                // 2. Save to DB immediately
                if (pack.quiz && pack.quiz.length > 0) {
                    const quizId = createDocId(grade, subject, safeUnitName, 'medium', language);
                    await setDoc(doc(db, 'quizzes', quizId), {
                        questions: pack.quiz,
                        createdAt: new Date().toISOString(),
                        source: 'ai_auto_gen'
                    });
                }

                if (pack.flashcards && pack.flashcards.length > 0) {
                    const flashId = createDocId(grade, subject, safeUnitName, language);
                    await setDoc(doc(db, 'flashcards', flashId), {
                        cards: pack.flashcards,
                        createdAt: new Date().toISOString(),
                        source: 'ai_auto_gen'
                    });
                }

                setGenProgress(((i + 1) / selectedUnits.length) * 100);
            }
            addLog("✅ All selected units generated and saved!");
        } catch (e: any) {
            addLog(`❌ Generator Error: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="max-w-4xl mx-auto p-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
                <div className="flex items-center justify-between mb-6 border-b border-slate-100 pb-4">
                    <div className="flex items-center gap-3">
                        <div className="bg-indigo-100 p-2 rounded-lg">
                            <Database className="w-6 h-6 text-indigo-600" />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-800">Database Admin</h2>
                            <p className="text-sm text-slate-500">Populate content for students</p>
                        </div>
                    </div>
                    {/* Mode Toggle */}
                    <div className="bg-slate-100 p-1 rounded-lg flex text-xs font-bold">
                        <button 
                            onClick={() => setMode('manual')}
                            className={`px-3 py-1.5 rounded-md transition-all ${mode === 'manual' ? 'bg-white shadow text-slate-800' : 'text-slate-500'}`}
                        >
                            Manual JSON
                        </button>
                        <button 
                            onClick={() => setMode('auto')}
                            className={`px-3 py-1.5 rounded-md transition-all flex items-center gap-1 ${mode === 'auto' ? 'bg-indigo-600 text-white shadow' : 'text-slate-500'}`}
                        >
                            <Sparkles className="w-3 h-3" /> AI Auto-Gen
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Settings Column */}
                    <div className="space-y-4">

                        {/* Grade & Language (Common) */}
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">Grade</label>
                                <select 
                                    value={grade} 
                                    onChange={(e) => setGrade(e.target.value)}
                                    className="w-full p-2 rounded-lg border border-slate-300 text-xs bg-white"
                                >
                                    {grades.map(g => <option key={g} value={g}>{g}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">Language</label>
                                <select 
                                    value={language} 
                                    onChange={(e) => setLanguage(e.target.value as any)}
                                    className="w-full p-2 rounded-lg border border-slate-300 text-xs bg-white"
                                >
                                    <option value="si">Sinhala</option>
                                    <option value="en">English</option>
                                </select>
                            </div>
                        </div>

                        {/* Mode Specific */}
                        {mode === 'manual' ? (
                            <>
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Upload Type</label>
                                    <div className="flex gap-2">
                                        <button 
                                            onClick={() => setUploadType('pack')}
                                            className={`flex-1 py-2 px-3 rounded-lg text-sm border ${uploadType === 'pack' ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'border-slate-200 text-slate-600'}`}
                                        >
                                            Study Pack
                                        </button>
                                        <button 
                                            onClick={() => setUploadType('syllabus')}
                                            className={`flex-1 py-2 px-3 rounded-lg text-sm border ${uploadType === 'syllabus' ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'border-slate-200 text-slate-600'}`}
                                        >
                                            Syllabus
                                        </button>
                                    </div>
                                </div>
                                {(uploadType === 'pack' || uploadType === 'syllabus') && (
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Subject</label>
                                        <input 
                                            type="text" 
                                            value={subject}
                                            onChange={(e) => setSubject(e.target.value)}
                                            placeholder="Ex: Science"
                                            className="w-full p-2.5 rounded-lg border border-slate-300 text-sm"
                                        />
                                    </div>
                                )}
                                <div className="border-2 border-dashed border-slate-300 rounded-xl p-6 flex flex-col items-center justify-center text-center cursor-pointer hover:bg-slate-50 relative">
                                    <input 
                                        type="file" 
                                        accept=".json"
                                        onChange={handleFileChange}
                                        className="absolute inset-0 opacity-0 cursor-pointer"
                                    />
                                    <FileJson className="w-8 h-8 text-slate-400 mb-2" />
                                    <span className="text-sm text-slate-600 font-medium">Click to upload JSON</span>
                                    {jsonContent && <span className="text-xs text-green-600 mt-1 font-bold flex items-center gap-1"><CheckCircle className="w-3 h-3" /> Selected</span>}
                                </div>
                                <Button onClick={handleUpload} disabled={isUploading || !jsonContent} className="w-full">
                                    {isUploading ? 'Uploading...' : 'Upload JSON'}
                                </Button>
                            </>
                        ) : (
                            <>
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Subject</label>
                                    <div className="flex gap-2">
                                        <input 
                                            type="text" 
                                            value={subject}
                                            onChange={(e) => setSubject(e.target.value)}
                                            placeholder="Ex: History"
                                            className="flex-1 p-2.5 rounded-lg border border-slate-300 text-sm"
                                        />
                                        <Button onClick={handleFetchUnits} disabled={isFetchingUnits || !subject} className="shrink-0">
                                            {isFetchingUnits ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Fetch Units'}
                                        </Button>
                                    </div>
                                </div>

                                {units.length > 0 && (
                                    <div className="bg-slate-50 rounded-xl p-3 border border-slate-200 max-h-[300px] overflow-y-auto">
                                        <div className="flex justify-between items-center mb-2">
                                            <span className="text-xs font-bold text-slate-700">Select Units to Generate</span>
                                            <button 
                                                onClick={() => setSelectedUnits(selectedUnits.length === units.length ? [] : [...units])}
                                                className="text-[10px] text-indigo-600 font-medium hover:underline"
                                            >
                                                {selectedUnits.length === units.length ? 'Deselect All' : 'Select All'}
                                            </button>
                                        </div>
                                        <div className="space-y-1">
                                            {units.map(unit => (
                                                <div key={unit} className="flex items-center gap-2 p-1.5 hover:bg-white rounded cursor-pointer" onClick={() => {
                                                    if (selectedUnits.includes(unit)) setSelectedUnits(selectedUnits.filter(u => u !== unit));
                                                    else setSelectedUnits([...selectedUnits, unit]);
                                                }}>
                                                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${selectedUnits.includes(unit) ? 'bg-indigo-600 border-indigo-600' : 'bg-white border-slate-300'}`}>
                                                        {selectedUnits.includes(unit) && <CheckCircle className="w-3 h-3 text-white" />}
                                                    </div>
                                                    <span className="text-xs text-slate-700">{unit}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {units.length > 0 && (
                                    <div className="space-y-2">
                                        {isGenerating && (
                                            <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                                                <div className="bg-indigo-600 h-full transition-all duration-300" style={{ width: `${genProgress}%` }}></div>
                                            </div>
                                        )}
                                        <Button 
                                            onClick={handleGenerateAll} 
                                            disabled={isGenerating || selectedUnits.length === 0} 
                                            className="w-full bg-gradient-to-r from-indigo-600 to-purple-600"
                                        >
                                            {isGenerating ? `Generating (${Math.round(genProgress)}%)...` : `Generate Content for ${selectedUnits.length} Units`}
                                        </Button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>

                    {/* Logs Column */}
                    <div className="bg-slate-900 rounded-xl p-4 text-xs font-mono text-slate-300 overflow-y-auto max-h-[500px] border border-slate-800 flex flex-col">
                        <div className="flex items-center justify-between border-b border-slate-800 pb-2 mb-3">
                            <div className="flex items-center gap-2 text-slate-500">
                                <FileText className="w-4 h-4" />
                                <span>System Logs</span>
                            </div>
                            <button 
                                onClick={handleTestConnection}
                                disabled={isUploading}
                                className="flex items-center gap-1 bg-slate-800 hover:bg-slate-700 text-slate-200 px-2 py-1 rounded border border-slate-700 transition-colors"
                            >
                                <Wifi className="w-3 h-3" />
                                Test Connection
                            </button>
                        </div>
                        <div className="flex-1 space-y-1">
                            {logs.length === 0 && <span className="text-slate-600 italic">Ready...</span>}
                            {logs.map((log, i) => (
                                <div key={i} className={log.includes('ERROR') || log.includes('FAILED') ? 'text-red-400' : log.includes('SUCCESS') || log.includes('PERFECTLY') ? 'text-green-400 font-bold' : ''}>
                                    {log}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule, Flashcard } from '../types';
import { SYLLABUS_DB, normalizeSubject, SyllabusUnit, GradeSyllabus } from '../data/syllabusDatabase';
import { db } from './firebase';
import { doc, getDoc, setDoc } from 'firebase/firestore';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// --- SMART HYBRID STRATEGY ---
const MODEL_COMPLEX = "gemini-3-pro-preview";
// Switched the 'Fast' model to be the primary for standard tasks to save money
const MODEL_FAST = "gemini-3-flash-preview"; 

const CACHE_PREFIX = 'nexus_plan_cache_';

/**
 * Generates a unique cache key.
 */
const getCacheKey = (params: any) => {
    const keyObj = {
        grade: params.grade,
        subjects: params.subjects.map((s: any) => s.name).sort().join(','),
        hours: params.hoursPerDay,
        examDate: params.routine.examDate,
        focus: params.focusArea,
        lang: params.language
    };
    return CACHE_PREFIX + btoa(encodeURIComponent(JSON.stringify(keyObj)));
};

/**
 * Helper to create safe Firestore Document IDs from user input
 * Removes special characters and spaces
 */
export const createDocId = (...parts: string[]) => {
    return parts
        .map(p => p.toLowerCase().trim().replace(/[^a-z0-9\u0D80-\u0DFF]+/gi, '_')) // Supports Sinhala chars + alphanumeric
        .join('__');
};

async function generateWithFallback(
    primaryModel: string, 
    fallbackModel: string, 
    params: any
) {
    try {
        return await ai.models.generateContent({
            ...params,
            model: primaryModel,
        });
    } catch (error: any) {
        const isQuotaError = 
            error.message?.includes('429') || 
            error.status === 429 ||
            error.status === 503;

        if (isQuotaError || fallbackModel) {
            console.warn(`⚠️ Model (${primaryModel}) failed. Switching to (${fallbackModel})...`);
            return await ai.models.generateContent({
                ...params,
                model: fallbackModel,
            });
        }
        throw error;
    }
}

// --- HYBRID DB GENERATION (Firebase -> Local -> AI) ---
async function generateFromDB(
    subjects: Subject[],
    grade: string,
    examDateStr: string,
    language: Language
): Promise<{ weeks: any[], tips: string[], isLocal: boolean } | null> {

    let gradeData: GradeSyllabus | undefined = undefined;

    // 1. Try Fetching from Firebase Firestore
    if (db) {
        try {
            // Using the grade string as the document ID (e.g., "10 ශ්‍රේණිය (Grade 10)")
            const docRef = doc(db, "syllabus", grade);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                console.log("✅ Fetched syllabus from Firebase Firestore");
                gradeData = docSnap.data() as GradeSyllabus;
            }
        } catch (e) {
            console.warn("⚠️ Firebase fetch failed (check config/internet). Falling back to local DB.", e);
        }
    }

    // 2. Fallback to Local DB if Firebase failed or data missing
    if (!gradeData) {
        console.log("ℹ️ Using Local Syllabus Database fallback");
        gradeData = SYLLABUS_DB[grade];
    }

    if (!gradeData) return null; // Both failed, use AI

    // 3. Process the Data (Mathematical Distribution)
    const relevantSyllabi: { name: string, units: SyllabusUnit[] }[] = [];

    subjects.forEach(sub => {
        const normalizedName = normalizeSubject(sub.name);
        // Check if gradeData has data for this subject
        if (gradeData && gradeData[normalizedName]) {
            relevantSyllabi.push({ name: sub.name, units: gradeData[normalizedName] });
        }
    });

    if (relevantSyllabi.length === 0) return null; 

    const today = new Date();
    const examDate = new Date(examDateStr);
    const diffTime = Math.abs(examDate.getTime() - today.getTime());
    const totalWeeks = Math.ceil(diffTime / (1000 * 60 * 60 * 24 * 7));

    const weeks = [];
    let currentWeekStart = new Date();

    // Loop through available weeks
    for (let i = 1; i <= totalWeeks; i++) {
        const weekStart = new Date(currentWeekStart);
        const weekEnd = new Date(currentWeekStart);
        weekEnd.setDate(weekEnd.getDate() + 6);

        // Round-robin assign units
        const weeklyGoals: string[] = [];

        relevantSyllabi.forEach(syllabus => {
            const unitIndex = Math.floor(((i - 1) / totalWeeks) * syllabus.units.length);
            if (syllabus.units[unitIndex]) {
                const u = syllabus.units[unitIndex];
                weeklyGoals.push(`${syllabus.name}: ${u.unit}`);
            }
        });

        let phase = "Foundation";
        if (i > totalWeeks * 0.6) phase = "Consolidation";
        if (i > totalWeeks * 0.85) phase = "Final Revision";

        weeks.push({
            weekNumber: i,
            startDate: weekStart.toISOString().split('T')[0],
            endDate: weekEnd.toISOString().split('T')[0],
            phase: phase,
            goal: weeklyGoals.length > 0 ? weeklyGoals.join(" | ") : "Review & Practice",
            sessions: [] 
        });

        currentWeekStart.setDate(currentWeekStart.getDate() + 7);
    }

    const tips = language === 'si' 
        ? ["කෙටි විවේක ලබා ගනිමින් පාඩම් කරන්න.", "පසුගිය විභාග ප්‍රශ්න පත්‍ර සාකච්ඡා කරන්න."]
        : ["Take short breaks using Pomodoro.", "Practice past papers regularly."];

    return { weeks, tips, isLocal: true };
}


// --- AI GENERATION ---
async function generateRoadmapBatch(
    startWeekNumber: number,
    startDateStr: string,
    endDateStr: string,
    isFirstBatch: boolean,
    params: {
        grade: string,
        subjectsStr: string,
        restDay: string,
        examContextInstruction: string,
        langContext: string,
        currentFormattedDate: string,
        examDate: string
    }
): Promise<any> {
    const prompt = `
    You are a Curriculum Expert for Sri Lanka's National Institute of Education (NIE).
    Task: Create a **PARTIAL ROADMAP** (${startDateStr} to ${endDateStr}).
    Part ${isFirstBatch ? '1' : '2'} of plan.

    Context:
    - Grade: ${params.grade}
    - Subjects: ${params.subjectsStr}

    **CRITICAL:** Use your search tool to find the official NIE syllabus for the specified grade and subjects to ensure the topics and their sequence are 100% accurate. Base the roadmap STRICTLY on the official curriculum.

    ${params.examContextInstruction}

    Strict Rules:
    1. **Accuracy:** Use search results for the syllabus. Do not guess.
    2. **Sequence:** Follow the official textbook/syllabus order precisely.
    3. **Start:** Begin at Week ${startWeekNumber}.

    **TOKEN SAVING:**
    1. Output JSON only. No explanations.
    2. ${isFirstBatch 
         ? `**Week ${startWeekNumber} to ${startWeekNumber + 1} ONLY:** Generate detailed 'sessions'. ALL other weeks must have an empty 'sessions' array ([]).` 
         : "ALL weeks must have an empty 'sessions' array ([])."}

    Output JSON: { "weeks": [{ "weekNumber": int, "startDate": "YYYY-MM-DD", "endDate": "YYYY-MM-DD", "phase": "string", "goal": "string", "sessions": [] }], "tips": ["string"] }
  `;

    // CHANGED: Use Pro model primarily for higher accuracy, with search enabled.
    const response = await generateWithFallback(MODEL_COMPLEX, MODEL_FAST, {
        contents: prompt,
        config: {
            tools: [{googleSearch: {}}],
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    weeks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                weekNumber: { type: Type.INTEGER },
                                startDate: { type: Type.STRING },
                                endDate: { type: Type.STRING },
                                phase: { type: Type.STRING },
                                goal: { type: Type.STRING },
                                sessions: {
                                    type: Type.ARRAY,
                                    items: {
                                        type: Type.OBJECT,
                                        properties: {
                                            day: { type: Type.STRING },
                                            subject: { type: Type.STRING },
                                            topic: { type: Type.STRING },
                                            technique: { type: Type.STRING },
                                            durationMinutes: { type: Type.NUMBER },
                                            startTime: { type: Type.STRING }
                                        },
                                        required: ["day", "subject", "topic"]
                                    }
                                }
                            },
                            required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
                        }
                    },
                    tips: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
        }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text.trim());

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sourceUrls = groundingChunks
        .map((chunk: any) => chunk.web?.uri)
        .filter((uri: string | undefined): uri is string => !!uri);

    return {
        weeks: data.weeks,
        tips: data.tips,
        sourceUrls: [...new Set(sourceUrls)]
    };
}


export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine,
  restDay: string = 'None',
  onProgress?: (percent: number) => void
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  let currentProgress = 0;
  let progressTimer: any | null = null;

  const updateProgress = (val: number) => {
      currentProgress = val;
      if (onProgress) onProgress(val);
  };

  const smoothProgressTo = (target: number) => {
      if (progressTimer) clearInterval(progressTimer);
      progressTimer = setInterval(() => {
          if (currentProgress < target) {
              const increment = Math.random() > 0.7 ? 2 : 1;
              if (currentProgress + increment <= target) {
                  updateProgress(currentProgress + increment);
              }
          }
      }, 200);
  };

  const stopProgressSimulation = () => {
      if (progressTimer) clearInterval(progressTimer);
      progressTimer = null;
  };

  try {
      const cacheKey = getCacheKey({ subjects, hoursPerDay, focusArea, grade, language, routine });
      const cachedData = localStorage.getItem(cacheKey);
      if (cachedData) {
          stopProgressSimulation();
          updateProgress(100);
          return JSON.parse(cachedData);
      }

      updateProgress(5);
      smoothProgressTo(20);

      // --- STRATEGY 1: TRY DATABASE (Firebase -> Local) (0 Credits) ---
      const dbPlan = await generateFromDB(subjects, grade, routine.examDate, language);

      if (dbPlan) {
        stopProgressSimulation();
        updateProgress(100);

        const plan: StudyPlan = {
            examDate: routine.examDate,
            weeks: dbPlan.weeks,
            tips: dbPlan.tips,
            sourceUrls: []
        };

        // Save to cache
        try { localStorage.setItem(cacheKey, JSON.stringify(plan)); } catch (e) {}
        return plan;
      }

      // --- STRATEGY 2: AI FALLBACK (Use Pro Model w/ Search) ---
      console.log("DB miss. Using AI (Pro Model w/ Search)...");

      const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

      const langContext = language === 'si' 
        ? "Sinhala language. Use Sinhala terms." 
        : "English language.";

      const today = new Date();
      const exam = new Date(routine.examDate);
      const diffTime = Math.abs(exam.getTime() - today.getTime());
      const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      const currentFormattedDate = today.toISOString().split('T')[0];

      let examContextInstruction = `Target: Grade ${grade}`;

      // Context analysis done
      stopProgressSimulation();
      updateProgress(25);

      const batchParams = {
          grade,
          subjectsStr,
          restDay,
          examContextInstruction,
          langContext,
          currentFormattedDate,
          examDate: routine.examDate
      };

      let mergedWeeks: any[] = [];
      let mergedTips: string[] = [];
      let mergedSourceUrls: string[] = [];

      if (daysUntilExam > 140) { 
          // Split into batches to avoid output token limits
          const midTime = today.getTime() + (diffTime / 2);
          const midDateStr = new Date(midTime).toISOString().split('T')[0];
          const weeksInFirstBatch = Math.ceil((midTime - today.getTime()) / (1000 * 60 * 60 * 24 * 7));

          smoothProgressTo(55);
          const batch1 = await generateRoadmapBatch(1, currentFormattedDate, midDateStr, true, batchParams);

          stopProgressSimulation();
          updateProgress(60);
          mergedWeeks = [...batch1.weeks];
          mergedTips = [...batch1.tips];
          mergedSourceUrls = [...new Set([...mergedSourceUrls, ...(batch1.sourceUrls || [])])];

          smoothProgressTo(65);
          await new Promise(resolve => setTimeout(resolve, 1000));

          smoothProgressTo(90);
          const lastWeekNum = batch1.weeks[batch1.weeks.length - 1]?.weekNumber || weeksInFirstBatch;
          const batch2 = await generateRoadmapBatch(lastWeekNum + 1, midDateStr, routine.examDate, false, batchParams);

          stopProgressSimulation();
          updateProgress(95);
          mergedWeeks = [...mergedWeeks, ...batch2.weeks];
          mergedSourceUrls = [...new Set([...mergedSourceUrls, ...(batch2.sourceUrls || [])])];

      } else {
          smoothProgressTo(85); 
          const batch = await generateRoadmapBatch(1, currentFormattedDate, routine.examDate, true, batchParams);
          stopProgressSimulation();
          updateProgress(90);
          mergedWeeks = batch.weeks;
          mergedTips = batch.tips;
          mergedSourceUrls = [...new Set([...mergedSourceUrls, ...(batch.sourceUrls || [])])];
      }

      const plan: StudyPlan = {
        examDate: routine.examDate,
        weeks: mergedWeeks,
        tips: mergedTips,
        sourceUrls: mergedSourceUrls,
      };

      try {
        localStorage.setItem(cacheKey, JSON.stringify(plan));
      } catch (e) {
        console.warn("Cache full");
      }

      updateProgress(100);
      return plan;
  } finally {
      stopProgressSimulation();
  }
};

