        Create DAILY SCHEDULE for **Week ${targetWeek.weekNumber}**.
        Grade: ${grade}
        Goal: ${targetWeek.goal}
        Date Range: ${targetWeek.startDate} to ${targetWeek.endDate}
        Hours/Day: ${hoursPerDay}
        Busy: ${busySlotsStr}
        Rest: ${restDay}
        School End: ${routine.schoolEndTime}
        Bed: ${routine.bedTime}

        Output JSON Array of sessions.
        Language: ${langContext}.
    `;

    // Switched to MODEL_FAST (Flash)
    const response = await generateWithFallback(MODEL_FAST, MODEL_COMPLEX, {
        contents: prompt,
        config: {
            // Disabled search to save time/cost
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                      day: { type: Type.STRING },
                      subject: { type: Type.STRING },
                      topic: { type: Type.STRING },
                      technique: { type: Type.STRING },
                      durationMinutes: { type: Type.NUMBER },
                      startTime: { type: Type.STRING }
                    },
                    required: ["day", "subject", "topic", "durationMinutes", "startTime"]
                }
            }
        }
    });

    const text = response.text;
    if (!text) throw new Error("No response");
    return JSON.parse(text.trim());
}


export const generateQuiz = async (
  subject: string, 
  topic: string, 
  subTopic: string, 
  questionCount: number,
  difficulty: string, 
  grade: string, 
  language: Language
): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const safeSubject = subject.trim().replace(/\s+/g, '_');
  const quizCollectionName = `quizzes_${safeSubject}`;
  const safeTopic = topic || 'general';

  // 1. Try to fetch from DB first (Save Credits)
  if (db) {
    try {
        const docId = createDocId(grade, safeTopic, difficulty, language);
        const docRef = doc(db, quizCollectionName, docId);
        const docSnap = await getDoc(docRef);

        if (docSnap.exists()) {
            console.log(`✅ Quiz fetched from Firebase: ${quizCollectionName}/${docId}`);
            return docSnap.data().questions as QuizQuestion[];
        }
    } catch (e) {
        console.warn("Quiz fetch error", e);
    }
  }

  // 2. Fallback to AI Generation
  console.log("Creating new Quiz via AI...");
  const response = await generateWithFallback(MODEL_FAST, MODEL_COMPLEX, {
    contents: `Generate ${questionCount} MCQs for ${grade} ${subject} on ${topic} ${subTopic ? '- ' + subTopic : ''}. Language: ${language}. Difficulty: ${difficulty}. Output JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctIndex: { type: Type.INTEGER },
            explanation: { type: Type.STRING }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");
  const questions = JSON.parse(text.trim()) as QuizQuestion[];

  // 3. Save to DB for next time
  if (db && questions.length > 0) {
    try {
        const docId = createDocId(grade, safeTopic, difficulty, language);
        await setDoc(doc(db, quizCollectionName, docId), { 
            questions,
            grade,
            subject,
            unit: safeTopic,
            difficulty,
            language,
            createdAt: new Date().toISOString() 
        });
        console.log(`💾 Quiz saved to Firebase: ${quizCollectionName}/${docId}`);
    } catch (e) {
        console.warn("Failed to save quiz", e);
    }
  }

  return questions;
};

