      Example: ["Unit 1: Motion", "Unit 2: Force"]
    `;

    const response = await generateWithFallback(MODEL_FAST, MODEL_COMPLEX, {
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
            }
        }
    });

    return JSON.parse(response.text?.trim() || "[]");
};

// 2. Generate Content for a Specific Unit
export const generateFullUnitPack = async (grade: string, subject: string, unit: string, language: Language) => {
    const prompt = `
      Create a Study Pack for:
      Grade: ${grade}
      Subject: ${subject}
      Unit: ${unit}
      Language: ${language === 'si' ? 'Sinhala' : 'English'}

      Tasks:
      1. 10 Multiple Choice Questions (Medium/Hard)
      2. 10 Flashcards (Concept on Front, Definition on Back)

      Return JSON.
    `;

    const response = await generateWithFallback(MODEL_COMPLEX, MODEL_FAST, {
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    quiz: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                                correctIndex: { type: Type.INTEGER },
                                explanation: { type: Type.STRING }
                            }
                        }
                    },
                    flashcards: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                front: { type: Type.STRING },
                                back: { type: Type.STRING }
